public class PlayerController : MonoBehaviour
{
    private Rigidbody2D rb;
    private bool isGrounded;

    void Start()
    {
        rb = GetComponent<Rigidbody2D>();
    }

    void Update()
    {
        isGrounded = IsGrounded();
    }

    bool IsGrounded()
    {
        // Check if the player's bottom collider is touching the ground's collider
        foreach (ContactPoint2D contact in rb.GetContacts())
        {
            if (contact.normal != Vector2.up) continue;
            return true;
        }
        return false;
    }
}
```

